import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { AdminLayout } from './components/admin/AdminLayout';

import { AdminArtists } from './pages/admin/artists/AdminArtists';
import { AdminArtistForm } from './pages/admin/artists/AdminArtistsForm';
import { AdminArtworks } from './pages/admin/artworks/AdminArtworks';
import { AdminBooks } from './pages/admin/books/AdminBooks';
import { AdminSections } from './pages/admin/sections/AdminSections';
import { AdminSeries } from './pages/admin/series/AdminSeries';
import { AdminTaxonomy } from './pages/admin/taxonomy/AdminTaxonomy';

function App() {
  return (
    <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
      <Routes>
        <Route path="/" element={
          <div className="flex items-center justify-center h-screen bg-black text-white font-serif italic text-4xl">
            Atlal Archive Under Construction
          </div>
        } />

        <Route path="/admin" element={<AdminLayout />}>
          <Route index element={<div className="text-white p-10 text-2xl">Welcome to the Atlal Control Room</div>} />
          
          <Route path="artists" element={<AdminArtists />} />
          <Route path="artists/new" element={<AdminArtistForm />} />
          <Route path="artists/add" element={<AdminArtistForm />} />
          
          <Route path="artworks" element={<AdminArtworks />} />
          <Route path="artworks/add" element={<div className="p-10 text-white">Artwork Cataloging Form</div>} />
          
          <Route path="books" element={<AdminBooks />} />
          <Route path="sections" element={<AdminSections />} />
          <Route path="series" element={<AdminSeries />} />
          <Route path="taxonomy" element={<AdminTaxonomy />} />
        </Route>
      </Routes>
    </Router>
  );
}

export default App;
